from collections import defaultdict
import re

class V_TwinSimulator:
    def __init__(self):
        self.index = defaultdict(set)

    def index_document(self, doc_id, text):
        """Index a document by tokenizing its text and storing term positions."""
        words = re.findall(r'\b\w+\b', text.lower())
        for word in words:
            self.index[word].add(doc_id)

    def search(self, query):
        """Return document IDs containing all query terms."""
        query_terms = re.findall(r'\b\w+\b', query.lower())
        if not query_terms:
            return set()
        result = self.index.get(query_terms[0], set())
        for term in query_terms[1:]:
            result.intersection_update(self.index.get(term, set()))
        return result

# Example usage:
vtwinsim = V_TwinSimulator()
vtwinsim.index_document(1, "Apple Advanced Technology Group founded in 1986")
vtwinsim.index_document(2, "ATG researched speech recognition and computer graphics")
print(vtwinsim.search("technology advanced"))  # Output: {1}
